import { useState } from 'react';
import { Calendar, Send } from 'lucide-react';
import { apiClient } from '../../../shared/api/apiClient';

export default function PostToGoogleCalendarWidget() {
  const [summary, setSummary] = useState('');
  const [description, setDescription] = useState('');
  const [startTime, setStartTime] = useState('');
  const [endTime, setEndTime] = useState('');
  const [location, setLocation] = useState('');
  const [attendeesStr, setAttendeesStr] = useState('');

  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [statusText, setStatusText] = useState('');

  const handlePost = async () => {
    if (!summary || !startTime || !endTime) return;

    setLoading(true);
    setStatus('idle');
    try {
      const attendees = attendeesStr.split(',').map(a => a.trim()).filter(a => a);

      await apiClient.post('/google/send-custom', {
        summary,
        description,
        startTime,
        endTime,
        location,
        attendees
      });

      setStatus('success');
      setStatusText('Event created successfully!');
      setSummary('');
      setDescription('');
      setStartTime('');
      setEndTime('');
      setLocation('');
      setAttendeesStr('');
      setTimeout(() => setStatus('idle'), 3000);
    } catch (err: any) {
      console.error(err);
      setStatus('error');
      setStatusText(err.response?.data?.error?.message || 'Failed to create event. Make sure Google Calendar is connected.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-card p-6 rounded-2xl border shadow-sm flex flex-col h-full overflow-y-auto">
      <div className="flex items-center gap-2 mb-6 shrink-0">
