import { useState, useEffect } from 'react';
import { Send, MessageSquare } from 'lucide-react';
import { apiClient } from '../../../shared/api/apiClient';

interface SlackChannel {
  id: string;
  name: string;
}

export default function PostToSlackWidget() {
  const [channels, setChannels] = useState<SlackChannel[]>([]);
  const [selectedChannel, setSelectedChannel] = useState('');
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [statusText, setStatusText] = useState('');

  useEffect(() => {
    const fetchChannels = async () => {
      try {
        const res = await apiClient.get('/slack/channels');
        if (res.data.success) {
          setChannels(res.data.data);
          if (res.data.data.length > 0) {
            setSelectedChannel(res.data.data[0].id);
          }
        }
      } catch (err: any) {
        console.error('Failed to fetch Slack channels', err);
        setStatus('error');
        setStatusText(err.response?.data?.error?.message || 'Failed to connect to Slack API');
      }
    };
    fetchChannels();
  }, []);

  const handlePost = async () => {
    if (!message.trim()) return;

    setLoading(true);
    setStatus('idle');
    try {
      await apiClient.post('/slack/send-custom', {
        channelId: selectedChannel,
        message
      });
      setStatus('success');
      setStatusText('Message posted successfully!');
      setMessage('');
      setTimeout(() => setStatus('idle'), 3000);
    } catch (err: any) {
      console.error(err);
      setStatus('error');
      setStatusText(err.response?.data?.error?.message || 'Failed to post message. Make sure Slack is connected.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-card p-6 rounded-2xl border shadow-sm flex flex-col h-full">
      <div className="flex items-center gap-2 mb-6">
        <MessageSquare className="w-5 h-5 text-primary" />
        <h2 className="text-lg font-semibold">Post to Slack</h2>
      </div>

      <div className="space-y-4 flex-1 flex flex-col">
        <div>
          <label className="block text-sm font-medium text-foreground mb-1">Channel</label>
          <select 
            className="w-full h-10 px-3 rounded-xl border border-input bg-background text-sm focus:ring-2 focus:ring-primary/20 outline-none"
            value={selectedChannel}
            onChange={(e) => setSelectedChannel(e.target.value)}
          >
            {channels.length === 0 && <option value="" disabled>No channels available</option>}
            {channels.map(c => (
              <option key={c.id} value={c.id}>#{c.name}</option>
            ))}
          </select>
          {status === 'error' && channels.length === 0 && (
            <p className="mt-1.5 text-xs text-danger">{statusText}</p>
          )}
        </div>

        <div className="flex-1 flex flex-col">
          <label className="block text-sm font-medium text-foreground mb-1">Message</label>
          <textarea 
            className="w-full flex-1 min-h-[100px] p-3 rounded-xl border border-input bg-background text-sm focus:ring-2 focus:ring-primary/20 outline-none resize-none"
            placeholder="Type your announcement or message here..."
            value={message}
            onChange={(e) => setMessage(e.target.value)}
          ></textarea>
        </div>

        {status !== 'idle' && (
          <div className={`text-sm p-2 rounded-lg ${status === 'success' ? 'bg-success/10 text-success' : 'bg-danger/10 text-danger'}`}>
            {statusText}
          </div>
        )}

        <button 
          onClick={handlePost}
          disabled={loading || !message.trim()}
          className="w-full h-10 bg-primary text-primary-foreground rounded-xl font-medium flex items-center justify-center hover:bg-primary/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {loading ? (
            <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
          ) : (
            <>
              <Send className="w-4 h-4 mr-2" />
              Post Message
            </>
          )}
        </button>
      </div>
    </div>
  );
}

import { apiClient } from '../../../shared/api/apiClient';
import type { EmployeeResponse } from '../types/employee';

export const getEmployees = async (page = 1, limit = 10, search = '', status = '') => {
  const params = new URLSearchParams({
    page: page.toString(),
    limit: limit.toString(),
  });

  if (search) params.append('search', search);
  if (status) params.append('status', status);

  const response = await apiClient.get<EmployeeResponse>(`/employees?${params.toString()}`);
  return response.data;
};

export const getEmployeeById = async (id: string) => {
  const response = await apiClient.get<EmployeeResponse>(`/employees/${id}`);
  return response.data;
};

export const createEmployee = async (data: any) => {
  const response = await apiClient.post<EmployeeResponse>('/employees', data);
  return response.data;
};

export const updateEmployee = async (id: string, data: any) => {
  const response = await apiClient.put<EmployeeResponse>(`/employees/${id}`, data);
  return response.data;
};

export const deleteEmployee = async (id: string) => {
  const response = await apiClient.delete<{ success: boolean; data: any }>(`/employees/${id}`);
  return response.data;
};

import { useState, useEffect } from 'react';
import { X, Save, Loader2, Upload, User as UserIcon } from 'lucide-react';
import { createEmployee, updateEmployee } from '../api/employeeService';
import { uploadFile } from '../../../shared/api/uploadService';
import { getImageUrl } from '../../../shared/utils/imageUrl';
import type { Employee } from '../types/employee';

interface EmployeeModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  employee?: Employee | null;
}

export default function EmployeeModal({ isOpen, onClose, onSuccess, employee }: EmployeeModalProps) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    password: '',
    role: 'Employee',
    employeeId: '',
    phone: '',
    status: 'Active',
    profilePicture: '',
  });

  const [uploadingImage, setUploadingImage] = useState(false);

  useEffect(() => {
    if (employee) {
      setFormData({
        firstName: employee.firstName,
        lastName: employee.lastName,
        email: employee.userId?.email || '',
        password: '',
        role: employee.userId?.role || 'Employee',
        employeeId: employee.employeeId,
        phone: employee.phone || '',
        status: employee.status,
        profilePicture: employee.profilePicture || '',
      });
    } else {
      setFormData({
        firstName: '',
        lastName: '',
        email: '',
        password: '',
        role: 'Employee',
        employeeId: 'EMP' + Math.floor(Math.random() * 10000),
        phone: '',
        status: 'Active',
        profilePicture: '',
      });
    }
    setError(null);
  }, [employee, isOpen]);

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (employee) {
        // Edit mode
        await updateEmployee(employee._id, {
          firstName: formData.firstName,
          lastName: formData.lastName,
          phone: formData.phone,
          status: formData.status,
          profilePicture: formData.profilePicture,
          role: formData.role,
        });
      } else {
        // Create mode
        await createEmployee(formData);
      }
      onSuccess();
      onClose();
    } catch (err: any) {
      setError(err.response?.data?.error?.message || 'Something went wrong');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm fade-in p-4">
      <div className="bg-background w-full max-w-xl rounded-2xl shadow-xl overflow-hidden flex flex-col max-h-[90vh]">

        <div className="flex items-center justify-between p-6 border-b">
          <h2 className="text-xl font-bold">{employee ? 'Edit Employee' : 'Add New Employee'}</h2>
          <button onClick={onClose} className="p-2 hover:bg-muted rounded-full transition-colors">
            <X className="h-5 w-5 text-muted-foreground" />
          </button>
        </div>

        <div className="overflow-y-auto p-6">
          {error && (
            <div className="mb-6 p-4 bg-danger/10 text-danger text-sm font-medium rounded-xl border border-danger/20">
              {error}
            </div>
          )}

          <form id="employee-form" onSubmit={handleSubmit} className="space-y-4">

            <div className="flex flex-col items-center justify-center space-y-4 mb-6">
              <div className="relative group">
                <div className="h-24 w-24 rounded-full border-4 border-background shadow-md overflow-hidden bg-muted flex items-center justify-center relative">
                  {formData.profilePicture ? (
                    <img src={getImageUrl(formData.profilePicture)} alt="Profile" className="h-full w-full object-cover" />
                  ) : (
                    <UserIcon className="h-10 w-10 text-muted-foreground opacity-50" />
                  )}
                  {uploadingImage && (
                    <div className="absolute inset-0 bg-background/50 flex items-center justify-center backdrop-blur-sm">
                      <Loader2 className="h-6 w-6 animate-spin text-primary" />
                    </div>
                  )}
                </div>
                <label className="absolute bottom-0 right-0 h-8 w-8 bg-primary text-primary-foreground rounded-full flex items-center justify-center shadow-lg cursor-pointer hover:bg-primary/90 transition-colors">
                  <Upload className="h-4 w-4" />
                  <input 
                    type="file" 
                    className="hidden" 
                    accept="image/*"
                    onChange={async (e) => {
                      if (e.target.files && e.target.files[0]) {
                        try {
                          setUploadingImage(true);
                          const url = await uploadFile(e.target.files[0]);
                          setFormData(prev => ({ ...prev, profilePicture: url }));
                        } catch (err) {
                          setError('Failed to upload image');
                        } finally {
                          setUploadingImage(false);
                        }
                      }
                    }}
                  />
                </label>
              </div>
              <span className="text-sm font-medium text-muted-foreground">Profile Picture</span>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-foreground">First Name *</label>
                <input
                  required
                  type="text"
                  className="w-full h-10 px-3 rounded-xl border border-border/50 bg-muted/30 hover:bg-muted/50 text-sm focus:bg-background focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                  value={formData.firstName}
                  onChange={(e) => setFormData({ ...formData, firstName: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-foreground">Last Name *</label>
                <input
                  required
                  type="text"
                  className="w-full h-10 px-3 rounded-xl border border-border/50 bg-muted/30 hover:bg-muted/50 text-sm focus:bg-background focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                  value={formData.lastName}
                  onChange={(e) => setFormData({ ...formData, lastName: e.target.value })}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-foreground">Email *</label>
                <input
                  required
                  disabled={!!employee}
                  type="email"
                  className="w-full h-10 px-3 rounded-xl border border-border/50 bg-muted/30 hover:bg-muted/50 text-sm focus:bg-background focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all disabled:opacity-50 disabled:hover:bg-muted/30"
                  value={formData.email}
                  onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                />
              </div>
              {!employee && (
