      <EmployeeModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSuccess={() => fetchEmployees()}
        employee={selectedEmployee}
      />

      <EmployeeDetailsModal
        isOpen={isDetailsOpen}
        onClose={() => setIsDetailsOpen(false)}
        employee={viewEmployee}
      />
    </div>
  );
}

import { apiClient } from '../../../shared/api/apiClient';
import type { LeaveResponse } from '../types/leave';

export const getLeaves = async (page = 1, limit = 10, status = '', leaveType = '') => {
  const params = new URLSearchParams({
    page: page.toString(),
    limit: limit.toString(),
  });

  if (status) params.append('status', status);
  if (leaveType) params.append('leaveType', leaveType);

  const response = await apiClient.get<LeaveResponse>(`/leaves?${params.toString()}`);
  return response.data;
};

export const applyLeave = async (data: any) => {
  const response = await apiClient.post<LeaveResponse>('/leaves', data);
  return response.data;
};

export const updateLeaveStatus = async (id: string, status: string, rejectionReason?: string) => {
  const response = await apiClient.patch<LeaveResponse>(`/leaves/${id}/status`, { status, rejectionReason });
  return response.data;
};

import React, { useState } from 'react';
import { X, Calendar as CalendarIcon, FileText } from 'lucide-react';
import { applyLeave } from '../api/leaveService';

interface LeaveApplicationModalProps {
  onClose: () => void;
  onSuccess: () => void;
}

export default function LeaveApplicationModal({ onClose, onSuccess }: LeaveApplicationModalProps) {
  const [leaveType, setLeaveType] = useState('Vacation');
  const [duration, setDuration] = useState('Full Day');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [reason, setReason] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!startDate || (duration === 'Full Day' && !endDate) || !reason) {
      setError('Please fill in all required fields.');
      return;
    }

    if (duration === 'Full Day' && new Date(startDate) > new Date(endDate)) {
      setError('End date cannot be before start date.');
      return;
    }

    try {
      setIsSubmitting(true);
      await applyLeave({
        leaveType,
        duration,
        startDate,
        endDate: duration === 'Full Day' ? endDate : startDate,
        reason,
      });
      onSuccess();
      onClose();
    } catch (err: any) {
      setError(err.response?.data?.error?.message || 'Failed to submit leave application.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm fade-in">
      <div className="bg-white w-full max-w-lg rounded-3xl p-8 shadow-2xl border border-border scale-in-center">

        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl font-bold text-foreground flex items-center">
            <CalendarIcon className="w-5 h-5 mr-2 text-primary" />
            Apply for Leave
          </h2>
          <button 
            onClick={onClose}
            className="p-2 hover:bg-muted rounded-full transition-colors"
          >
            <X className="w-5 h-5 text-muted-foreground" />
          </button>
        </div>

        {error && (
          <div className="mb-4 p-3 bg-danger/10 border border-danger/20 text-danger rounded-xl text-sm">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-sm font-medium text-foreground mb-1.5">Leave Type</label>
            <select
              value={leaveType}
              onChange={(e) => setLeaveType(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
            >
              <option value="Vacation">Vacation</option>
              <option value="Sick">Sick Leave</option>
              <option value="Maternity">Maternity Leave</option>
              <option value="Paternity">Paternity Leave</option>
              <option value="Unpaid">Unpaid Leave</option>
              <option value="Other">Other</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-foreground mb-1.5">Duration</label>
            <div className="flex bg-background border border-border p-1 rounded-xl">
              {['Full Day', 'First Half', 'Second Half'].map(d => (
                <button
                  key={d}
                  type="button"
                  onClick={() => setDuration(d)}
                  className={`flex-1 py-2 text-sm font-medium rounded-lg transition-all ${duration === d ? 'bg-primary text-primary-foreground shadow-sm' : 'text-muted-foreground hover:text-foreground hover:bg-muted/50'}`}
                >
                  {d}
                </button>
              ))}
            </div>
          </div>

          <div className={`grid ${duration === 'Full Day' ? 'grid-cols-2' : 'grid-cols-1'} gap-4`}>
            <div>
              <label className="block text-sm font-medium text-foreground mb-1.5">{duration === 'Full Day' ? 'Start Date' : 'Date'}</label>
              <input
                type="date"
                required
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
              />
            </div>
            {duration === 'Full Day' && (
              <div>
                <label className="block text-sm font-medium text-foreground mb-1.5">End Date</label>
                <input
                  type="date"
                  required
                  value={endDate}
                  min={startDate}
                  onChange={(e) => setEndDate(e.target.value)}
                  className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                />
              </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-foreground mb-1.5">Reason</label>
            <div className="relative">
              <textarea
                required
                rows={3}
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                placeholder="Briefly explain the reason for your leave..."
                className="w-full pl-11 pr-4 py-3 rounded-xl border border-border bg-background text-foreground focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all resize-none"
              />
              <FileText className="absolute left-4 top-3.5 w-5 h-5 text-muted-foreground" />
            </div>
          </div>

          <div className="flex justify-end gap-3 pt-6 border-t border-border mt-2">
            <button
              type="button"
              onClick={onClose}
              disabled={isSubmitting}
              className="px-6 py-3 rounded-xl text-sm font-bold text-muted-foreground hover:bg-muted hover:text-foreground transition-all"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isSubmitting}
              className="px-6 py-3 rounded-xl text-sm font-bold bg-primary text-primary-foreground hover:bg-primary/90 transition-all disabled:opacity-50 shadow-md hover:shadow-lg active:scale-95"
            >
              {isSubmitting ? 'Submitting...' : 'Submit Application'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Plus, Umbrella, HeartPulse, Clock, FileWarning, CheckCircle2, XCircle, X } from 'lucide-react';
import { getLeaves, updateLeaveStatus } from '../api/leaveService';
import RoleGuard from '../../../shared/components/RoleGuard';
import { useAuth } from '../../../shared/context/AuthContext';
import LeaveApplicationModal from '../components/LeaveApplicationModal';
import type { Leave } from '../types/leave';

export default function LeaveList() {
  const [leaves, setLeaves] = useState<Leave[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState('');
  const [typeFilter, setTypeFilter] = useState('');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalRecords, setTotalRecords] = useState(0);

  const [rejectingLeaveId, setRejectingLeaveId] = useState<string | null>(null);
  const [rejectionReason, setRejectionReason] = useState('');
  const [rejectError, setRejectError] = useState('');

  const [showApplyModal, setShowApplyModal] = useState(false);

  const { user } = useAuth();
  const isAdminOrManager = user && ['Admin', 'Manager', 'HR'].includes(user.role);

  const fetchLeaves = async () => {
    try {
      setLoading(true);
      const res = await getLeaves(page, 10, statusFilter, typeFilter);
      if (res.success && Array.isArray(res.data)) {
        setLeaves(res.data);
        if (res.pagination) {
          setTotalPages(res.pagination.totalPages);
          setTotalRecords(res.pagination.total);
        }
      }
    } catch (error) {
      console.error('Failed to fetch leaves', error);
      setLeaves([]);
    } finally {
      setLoading(false);
    }
  };

  const handleStatusUpdate = async (leaveId: string, newStatus: string, reason?: string) => {
    if (newStatus === 'Rejected' && !reason) {
      setRejectingLeaveId(leaveId);
      setRejectionReason('');
      setRejectError('');
      return;
    }

    try {
      await updateLeaveStatus(leaveId, newStatus, reason);
      fetchLeaves();
    } catch (error) {
      console.error('Failed to update leave status', error);
      alert('Failed to update leave status');
    }
  };

  const submitRejection = () => {
    if (!rejectionReason.trim()) {
      setRejectError("A rejection reason is required.");
      return;
    }
    if (rejectingLeaveId) {
      handleStatusUpdate(rejectingLeaveId, 'Rejected', rejectionReason);
      setRejectingLeaveId(null);
      setRejectError('');
    }
  };

  useEffect(() => {
    const delayDebounceFn = setTimeout(() => {
      fetchLeaves();
    }, 300);
    return () => clearTimeout(delayDebounceFn);
  }, [page, statusFilter, typeFilter]);

  const getLeaveIcon = (type: string) => {
    switch (type) {
      case 'Sick': return <HeartPulse className="h-5 w-5 text-danger" />;
      case 'Vacation': return <Umbrella className="h-5 w-5 text-primary" />;
      default: return <Clock className="h-5 w-5 text-muted-foreground" />;
    }
  };

  return (
    <div className="w-full max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8 space-y-6 fade-in">

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-foreground">Leave Management</h1>
          <p className="text-muted-foreground mt-1">Track and manage time-off requests.</p>
        </div>
        <RoleGuard allowedRoles={['Employee']}>
          <button 
            onClick={() => setShowApplyModal(true)}
            className="inline-flex items-center justify-center rounded-full text-sm font-medium transition-colors bg-primary text-primary-foreground hover:bg-primary/90 h-10 px-6 py-2 shadow-sm"
          >
            <Plus className="mr-2 h-4 w-4" />
            Apply for Leave
          </button>
        </RoleGuard>
      </div>

      <div className="flex flex-col sm:flex-row gap-4 justify-between items-center bg-card p-2 rounded-2xl border shadow-sm">
        <div className="flex items-center gap-2 w-full sm:w-auto ml-auto">
          <select 
            className="h-10 px-4 rounded-xl border bg-background text-sm font-medium outline-none focus:ring-2 focus:ring-primary/20 transition-all"
            value={typeFilter}
            onChange={(e) => setTypeFilter(e.target.value)}
          >
            <option value="">All Leave Types</option>
            <option value="Sick">Sick Leave</option>
            <option value="Vacation">Vacation</option>
            <option value="Maternity">Maternity</option>
            <option value="Paternity">Paternity</option>
            <option value="Unpaid">Unpaid</option>
            <option value="Other">Other</option>
          </select>

          <select 
            className="h-10 px-4 rounded-xl border bg-background text-sm font-medium outline-none focus:ring-2 focus:ring-primary/20 transition-all"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
