import { useEffect, useState } from 'react';
import { Plus, DollarSign, Download, CircleCheck, CircleDashed, Filter } from 'lucide-react';
import { getPayrollRecords, updatePayrollStatus } from '../api/payrollService';
import { useAuth } from '../../../shared/context/AuthContext';
import PayrollModal from '../components/PayrollModal';
import type { Payroll } from '../types/payroll';

export default function PayrollList() {
  const [records, setRecords] = useState<Payroll[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState('');
  const [monthFilter, setMonthFilter] = useState('');
  const [yearFilter, setYearFilter] = useState<number | undefined>(undefined);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalRecords, setTotalRecords] = useState(0);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const { user } = useAuth();
  const isHR = user && user.role === 'HR';

  const fetchRecords = async () => {
    try {
      setLoading(true);
      const res = await getPayrollRecords(page, 10, statusFilter, monthFilter, yearFilter);
      if (res.success && Array.isArray(res.data)) {
        setRecords(res.data);
        if (res.pagination) {
          setTotalPages(res.pagination.totalPages);
          setTotalRecords(res.pagination.total);
        }
      }
    } catch (error) {
      console.error('Failed to fetch payroll records', error);
      setRecords([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRecords();
  }, [page, statusFilter, monthFilter, yearFilter]);

  const handleStatusUpdate = async (id: string, newStatus: string) => {
    try {
      await updatePayrollStatus(id, newStatus);
      fetchRecords();
    } catch (error) {
      console.error('Failed to update payroll status', error);
      alert('Failed to update payroll status');
    }
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      minimumFractionDigits: 0
    }).format(amount);
  };

  const handleExportCSV = () => {
    if (records.length === 0) {
      alert("No records to export.");
      return;
    }

    const headers = ['Employee Name', 'Employee ID', 'Month', 'Year', 'Base Salary', 'Bonus', 'Deductions', 'Net Pay', 'Status'];
    const rows = records.map(r => [
      `${r.employeeId?.firstName || ''} ${r.employeeId?.lastName || ''}`,
      r.employeeId?.employeeId || 'EMP-XXXX',
      r.month,
      r.year,
      r.baseSalary,
      r.bonus,
      r.deductions,
      r.netPay,
      r.status
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(r => r.join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `Payroll_Export_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'Paid': return 'bg-success/10 text-success border-success/20';
      case 'Processed': return 'bg-primary/10 text-primary border-primary/20';
      default: return 'bg-warning/10 text-warning border-warning/20';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'Paid': return <CircleCheck className="h-3 w-3 mr-1" />;
      default: return <CircleDashed className="h-3 w-3 mr-1" />;
    }
  };

  return (
    <div className="w-full max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8 space-y-6 fade-in">

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-foreground">Payroll</h1>
          <p className="text-muted-foreground mt-1">Manage employee compensation, bonuses, and deductions.</p>
        </div>
        <div className="flex items-center gap-3">
          <button 
            onClick={handleExportCSV}
            className="inline-flex items-center justify-center rounded-full text-sm font-medium transition-colors bg-secondary text-secondary-foreground hover:bg-secondary/80 h-10 px-6 py-2 shadow-sm border"
          >
            <Download className="mr-2 h-4 w-4" />
            Export CSV
          </button>
          {isHR && (
            <button 
              onClick={() => setIsModalOpen(true)}
              className="inline-flex items-center justify-center rounded-full text-sm font-medium transition-colors bg-primary text-primary-foreground hover:bg-primary/90 h-10 px-6 py-2 shadow-sm"
            >
              <Plus className="mr-2 h-4 w-4" />
              Process Payroll
            </button>
          )}
        </div>
      </div>

      <div className="flex flex-col sm:flex-row gap-4 justify-between items-center bg-card p-2 rounded-2xl border shadow-sm">
        <div className="flex items-center gap-2 w-full sm:w-auto overflow-x-auto px-2">
          <Filter className="h-4 w-4 text-muted-foreground mr-1" />
          <select 
            className="h-10 px-4 rounded-xl border bg-background text-sm font-medium outline-none focus:ring-2 focus:ring-primary/20 transition-all min-w-[120px]"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="">All Statuses</option>
            <option value="Pending">Pending</option>
            <option value="Processed">Processed</option>
            <option value="Paid">Paid</option>
          </select>

          <select 
            className="h-10 px-4 rounded-xl border bg-background text-sm font-medium outline-none focus:ring-2 focus:ring-primary/20 transition-all min-w-[120px]"
            value={monthFilter}
            onChange={(e) => setMonthFilter(e.target.value)}
          >
            <option value="">All Months</option>
            {['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'].map(m => (
              <option key={m} value={m}>{m}</option>
            ))}
          </select>

          <select 
            className="h-10 px-4 rounded-xl border bg-background text-sm font-medium outline-none focus:ring-2 focus:ring-primary/20 transition-all min-w-[120px]"
            value={yearFilter || ''}
            onChange={(e) => setYearFilter(e.target.value ? parseInt(e.target.value) : undefined)}
          >
            <option value="">All Years</option>
            {[2024, 2025, 2026, 2027].map(y => (
              <option key={y} value={y}>{y}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="bg-card rounded-2xl border shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-muted/50 text-muted-foreground uppercase text-xs font-semibold border-b">
              <tr>
                <th className="px-6 py-4">Employee</th>
                <th className="px-6 py-4">Period</th>
                <th className="px-6 py-4">Base Salary</th>
                <th className="px-6 py-4">Add/Ded</th>
                <th className="px-6 py-4 font-bold text-foreground">Net Pay</th>
                <th className="px-6 py-4">Status</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                [1, 2, 3, 4, 5].map(i => (
                  <tr key={i} className="border-b last:border-0 animate-pulse">
                    <td className="px-6 py-4"><div className="h-4 bg-muted rounded w-32"></div></td>
                    <td className="px-6 py-4"><div className="h-4 bg-muted rounded w-20"></div></td>
                    <td className="px-6 py-4"><div className="h-4 bg-muted rounded w-24"></div></td>
                    <td className="px-6 py-4"><div className="h-4 bg-muted rounded w-16"></div></td>
                    <td className="px-6 py-4"><div className="h-5 bg-muted rounded w-24"></div></td>
                    <td className="px-6 py-4"><div className="h-6 bg-muted rounded-full w-24"></div></td>
                  </tr>
                ))
              ) : records.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-16 text-center text-muted-foreground">
                    <div className="flex flex-col items-center justify-center">
                      <div className="bg-muted p-4 rounded-full mb-4">
                        <DollarSign className="h-8 w-8 opacity-50" />
                      </div>
                      <h3 className="text-lg font-semibold text-foreground">No payroll records found</h3>
                      <p className="mt-1">Try adjusting your filters or process a new payroll batch.</p>
                    </div>
                  </td>
                </tr>
              ) : (
                records.map((record) => (
                  <tr key={record._id} className="border-b last:border-0 hover:bg-muted/30 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="h-9 w-9 rounded-full bg-primary/10 text-primary flex items-center justify-center font-bold text-xs">
                          {record.employeeId?.firstName?.charAt(0)}{record.employeeId?.lastName?.charAt(0)}
                        </div>
                        <div>
                          <p className="font-medium text-foreground">{record.employeeId?.firstName} {record.employeeId?.lastName}</p>
                          <p className="text-xs text-muted-foreground">{record.employeeId?.employeeId || 'EMP-XXXX'}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <p className="font-medium text-foreground">{record.month}</p>
                      <p className="text-xs text-muted-foreground">{record.year}</p>
                    </td>
                    <td className="px-6 py-4 text-muted-foreground">
                      {formatCurrency(record.baseSalary)}
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-1 text-xs">
                        {record.bonus > 0 && <span className="text-success">+{formatCurrency(record.bonus)}</span>}
                        {record.deductions > 0 && <span className="text-danger">-{formatCurrency(record.deductions)}</span>}
                        {record.bonus === 0 && record.deductions === 0 && <span className="text-muted-foreground">-</span>}
                      </div>
                    </td>
                    <td className="px-6 py-4 font-bold text-foreground">
                      {formatCurrency(record.netPay)}
                    </td>
                    <td className="px-6 py-4">
                      {isHR ? (
                        <div className="relative inline-flex items-center">
                          <div className={`absolute left-2.5 pointer-events-none flex items-center justify-center ${getStatusColor(record.status).split(' ')[1]}`}>
                            {getStatusIcon(record.status)}
                          </div>
                          <select
                            value={record.status}
                            onClick={(e) => e.stopPropagation()}
                            onChange={(e) => handleStatusUpdate(record._id, e.target.value)}
                            className={`appearance-none cursor-pointer outline-none pl-7 pr-6 py-1 rounded-full text-xs font-semibold transition-colors border hover:border-border/50
                              ${getStatusColor(record.status)}
                            `}
                          >
                            <option value="Pending" className="text-foreground bg-background">Pending</option>
                            <option value="Processed" className="text-foreground bg-background">Processed</option>
                            <option value="Paid" className="text-foreground bg-background">Paid</option>
                          </select>
                          <div className="absolute right-2 pointer-events-none opacity-50">
                            <svg className="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                          </div>
                        </div>
                      ) : (
                        <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-semibold border ${getStatusColor(record.status)}`}>
                          {getStatusIcon(record.status)}
                          {record.status}
                        </span>
                      )}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {!loading && records.length > 0 && (
        <div className="flex items-center justify-between pt-2">
          <span className="text-sm text-muted-foreground">
            Showing <span className="font-medium text-foreground">{totalRecords}</span> records
          </span>
          <div className="flex items-center gap-2">
            <button 
              onClick={() => setPage(p => Math.max(1, p - 1))}
              disabled={page === 1}
              className="px-3 py-1.5 rounded-lg border bg-background text-sm font-medium hover:bg-muted disabled:opacity-50 transition-colors"
            >
              Previous
            </button>
            <button 
              onClick={() => setPage(p => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
              className="px-3 py-1.5 rounded-lg border bg-background text-sm font-medium hover:bg-muted disabled:opacity-50 transition-colors"
            >
              Next
            </button>
          </div>
        </div>
      )}

      <PayrollModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSuccess={fetchRecords} 
      />
    </div>
  );
}

import { apiClient } from '../../../shared/api/apiClient';
import type { ProjectResponse } from '../types/project';

export const getProjects = async (page = 1, limit = 10, search = '', status = '') => {
  const params = new URLSearchParams({
    page: page.toString(),
    limit: limit.toString(),
  });

  if (search) params.append('search', search);
  if (status) params.append('status', status);

  const response = await apiClient.get<ProjectResponse>(`/projects?${params.toString()}`);
  return response.data;
};

export const createProject = async (data: any) => {
  const response = await apiClient.post<ProjectResponse>('/projects', data);
  return response.data;
};

export const updateProject = async (id: string, data: any) => {
  const response = await apiClient.put<ProjectResponse>(`/projects/${id}`, data);
  return response.data;
};

export const deleteProject = async (id: string) => {
  const response = await apiClient.delete(`/projects/${id}`);
  return response.data;
};

import { useState, useEffect } from 'react';
import { X, Save, Loader2 } from 'lucide-react';
import { createProject, updateProject } from '../api/projectService';
import { getClients } from '../../clients/api/clientService';
import { getEmployees } from '../../employees/api/employeeService';
import type { Project } from '../types/project';
import type { Client } from '../../clients/types/client';
import type { Employee } from '../../employees/types/employee';

interface ProjectModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
  project?: Project | null;
}

export default function ProjectModal({ isOpen, onClose, onSuccess, project }: ProjectModalProps) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [clients, setClients] = useState<Client[]>([]);
  const [employees, setEmployees] = useState<Employee[]>([]);

  const [formData, setFormData] = useState({
    name: '',
    description: '',
    clientId: '',
    status: 'Planning',
    priority: 'Medium',
    startDate: new Date().toISOString().split('T')[0],
    deadline: new Date(new Date().setDate(new Date().getDate() + 30)).toISOString().split('T')[0],
    teamMembers: [] as string[],
  });

  useEffect(() => {
    if (!isOpen) return;

    // Fetch clients and employees for dropdowns
    const fetchData = async () => {
      try {
        const [clientsRes, employeesRes] = await Promise.all([
          getClients(1, 100, ''),
          getEmployees(1, 100, '')
        ]);
        if (clientsRes.success && Array.isArray(clientsRes.data)) setClients(clientsRes.data);
        if (employeesRes.success && Array.isArray(employeesRes.data)) setEmployees(employeesRes.data);
      } catch (err) {
        console.error('Failed to fetch dependencies', err);
      }
    };
    fetchData();

    if (project) {
      setFormData({
        name: project.name,
        description: project.description,
        clientId: project.clientId?._id || '',
        status: project.status,
        priority: project.priority,
        startDate: new Date(project.startDate).toISOString().split('T')[0],
        deadline: new Date(project.deadline).toISOString().split('T')[0],
        teamMembers: project.teamMembers?.map(m => m._id) || [],
      });
    } else {
      setFormData({
        name: '',
        description: '',
        clientId: '',
        status: 'Planning',
        priority: 'Medium',
        startDate: new Date().toISOString().split('T')[0],
        deadline: new Date(new Date().setDate(new Date().getDate() + 30)).toISOString().split('T')[0],
        teamMembers: [],
      });
    }
    setError(null);
  }, [project, isOpen]);

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    // Filter out empty clientId if left empty
    const payload = {
      ...formData,
      clientId: formData.clientId || null,
    };

    try {
      if (project) {
        await updateProject(project._id, payload);
      } else {
        await createProject(payload);
      }
      onSuccess();
      onClose();
    } catch (err: any) {
      setError(err.response?.data?.error?.message || 'Something went wrong');
    } finally {
      setLoading(false);
    }
  };

  const toggleTeamMember = (empId: string) => {
    setFormData(prev => {
      const isSelected = prev.teamMembers.includes(empId);
      if (isSelected) {
        return { ...prev, teamMembers: prev.teamMembers.filter(id => id !== empId) };
      } else {
        return { ...prev, teamMembers: [...prev.teamMembers, empId] };
      }
    });
  };

  const inputClass = "w-full h-10 px-3 rounded-xl border border-border/50 bg-muted/30 hover:bg-muted/50 text-sm focus:bg-background focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all disabled:opacity-50 disabled:hover:bg-muted/30";

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm fade-in p-4">
      <div className="bg-background w-full max-w-2xl rounded-2xl shadow-xl overflow-hidden flex flex-col max-h-[90vh]">

        <div className="flex items-center justify-between p-6 border-b">
          <h2 className="text-xl font-bold">{project ? 'Edit Project' : 'Create New Project'}</h2>
          <button onClick={onClose} className="p-2 hover:bg-muted rounded-full transition-colors">
            <X className="h-5 w-5 text-muted-foreground" />
          </button>
        </div>

        <div className="overflow-y-auto p-6">
          {error && (
            <div className="mb-6 p-4 bg-danger/10 text-danger text-sm font-medium rounded-xl border border-danger/20">
              {error}
            </div>
          )}

          <form id="project-form" onSubmit={handleSubmit} className="space-y-4">
            <div className="space-y-2">
              <label className="text-sm font-medium text-foreground">Project Name *</label>
              <input
                required
                type="text"
                className={inputClass}
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              />
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-foreground">Description</label>
              <textarea
                rows={3}
                className="w-full p-3 rounded-xl border border-border/50 bg-muted/30 hover:bg-muted/50 text-sm focus:bg-background focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all resize-none"
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-foreground">Client</label>
                <select
                  className={inputClass}
                  value={formData.clientId}
                  onChange={(e) => setFormData({ ...formData, clientId: e.target.value })}
                >
                  <option value="">Internal Project (No Client)</option>
                  {clients.map(client => (
                    <option key={client._id} value={client._id}>{client.companyName}</option>
                  ))}
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-medium text-foreground">Priority</label>
                <select
                  className={inputClass}
                  value={formData.priority}
                  onChange={(e) => setFormData({ ...formData, priority: e.target.value })}
                >
                  <option value="Low">Low Priority</option>
                  <option value="Medium">Medium Priority</option>
                  <option value="High">High Priority</option>
                </select>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-sm font-medium text-foreground">Start Date *</label>
                <input
                  required
                  type="date"
                  className={inputClass}
                  value={formData.startDate}
                  onChange={(e) => setFormData({ ...formData, startDate: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium text-foreground">Deadline *</label>
                <input
                  required
                  type="date"
                  className={inputClass}
                  value={formData.deadline}
                  onChange={(e) => setFormData({ ...formData, deadline: e.target.value })}
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium text-foreground">Status</label>
              <select
                className={inputClass}
                value={formData.status}
                onChange={(e) => setFormData({ ...formData, status: e.target.value })}
              >
                <option value="Planning">Planning</option>
                <option value="In Progress">In Progress</option>
                <option value="On Hold">On Hold</option>
                <option value="Completed">Completed</option>
              </select>
            </div>

            <div className="space-y-2 pt-2">
              <label className="text-sm font-medium text-foreground">Team Members</label>
              <div className="max-h-40 overflow-y-auto rounded-xl border border-border/50 bg-muted/30 p-2 space-y-1">
                {employees.length === 0 ? (
                  <p className="text-xs text-muted-foreground p-2 text-center">No employees found.</p>
                ) : (
                  employees.map(emp => (
                    <label key={emp._id} className="flex items-center gap-3 p-2 hover:bg-background rounded-lg cursor-pointer transition-colors border border-transparent hover:border-border/50">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-border text-primary focus:ring-primary/20"
                        checked={formData.teamMembers.includes(emp._id)}
                        onChange={() => toggleTeamMember(emp._id)}
                      />
                      <div className="flex items-center gap-2">
                        <div className="h-6 w-6 rounded-full bg-primary/10 text-primary flex items-center justify-center text-[10px] font-bold">
                          {emp.firstName.charAt(0)}{emp.lastName.charAt(0)}
                        </div>
                        <span className="text-sm font-medium">{emp.firstName} {emp.lastName}</span>
                        {emp.userId?.role && <span className="text-xs text-muted-foreground ml-auto">({emp.userId.role})</span>}
                      </div>
                    </label>
                  ))
                )}
              </div>
            </div>

          </form>
        </div>

        <div className="p-6 border-t bg-muted/20 flex justify-end gap-3 mt-auto">
          <button 
            type="button" 
            onClick={onClose}
            className="px-6 py-2 rounded-full font-medium border bg-background hover:bg-muted transition-colors text-sm"
          >
            Cancel
          </button>
          <button 
            type="submit" 
            form="project-form"
            disabled={loading}
            className="px-6 py-2 rounded-full font-medium bg-primary text-primary-foreground hover:bg-primary/90 transition-colors text-sm flex items-center shadow-sm disabled:opacity-50"
          >
            {loading ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <Save className="h-4 w-4 mr-2" />}
            {project ? 'Save Changes' : 'Create Project'}
          </button>
        </div>

      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Search, Plus, Target, Calendar, Flag, AlertCircle, CircleDashed } from 'lucide-react';
import { getProjects, deleteProject, updateProject } from '../api/projectService';
import type { Project } from '../types/project';
import ProjectDetailsModal from '../components/ProjectDetailsModal';
import ProjectModal from '../components/ProjectModal';
import { Edit, Trash2 } from 'lucide-react';
import RoleGuard from '../../../shared/components/RoleGuard';

export default function ProjectList() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalRecords, setTotalRecords] = useState(0);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDetailsModalOpen, setIsDetailsModalOpen] = useState(false);
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);

  const handleAdd = () => {
    setSelectedProject(null);
    setIsModalOpen(true);
  };

  const handleEdit = (project: Project) => {
    setSelectedProject(project);
    setIsModalOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Are you sure you want to delete this project?')) {
      try {
        await deleteProject(id);
        fetchProjects();
      } catch (error) {
        console.error('Failed to delete project', error);
        alert('Failed to delete project');
      }
    }
  };

  const handleStatusChange = async (project: Project, newStatus: string) => {
    try {
      await updateProject(project._id, { status: newStatus });
      fetchProjects();
    } catch (error) {
      console.error('Failed to update status', error);
      alert('Failed to update status');
    }
  };

  const handleViewDetails = (project: Project) => {
    setSelectedProject(project);
    setIsDetailsModalOpen(true);
  };

  const fetchProjects = async () => {
    try {
      setLoading(true);
      const res = await getProjects(page, 10, search, statusFilter);
      if (res.success && Array.isArray(res.data)) {
        setProjects(res.data);
        if (res.pagination) {
          setTotalPages(res.pagination.totalPages);
          setTotalRecords(res.pagination.total);
        }
      }
    } catch (error) {
      console.error('Failed to fetch projects', error);
      setProjects([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const delayDebounceFn = setTimeout(() => {
      fetchProjects();
    }, 300);
    return () => clearTimeout(delayDebounceFn);
  }, [page, search, statusFilter]);

  return (
    <div className="w-full max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8 space-y-6 fade-in">

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-foreground">Projects</h1>
          <p className="text-muted-foreground mt-1">Track deliverables, timelines, and team resourcing.</p>
        </div>
        <RoleGuard allowedRoles={['Admin', 'Manager']}>
          <button 
            onClick={handleAdd}
            className="inline-flex items-center justify-center rounded-full text-sm font-medium transition-colors bg-primary text-primary-foreground hover:bg-primary/90 h-10 px-6 py-2 shadow-sm"
          >
            <Plus className="mr-2 h-4 w-4" />
            New Project
          </button>
        </RoleGuard>
      </div>

      <div className="flex flex-col sm:flex-row gap-4 justify-between items-center bg-card p-2 rounded-2xl border shadow-sm">
        <div className="relative w-full sm:w-96 flex items-center">
          <Search className="absolute left-3 h-4 w-4 text-muted-foreground" />
          <input
            type="text"
            placeholder="Search projects..."
            className="w-full h-10 pl-10 pr-4 rounded-xl border-none bg-muted/50 focus:bg-background focus:ring-2 focus:ring-primary/20 transition-all text-sm outline-none"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>
        <div className="flex items-center gap-2 w-full sm:w-auto">
          <select 
            className="h-10 px-4 rounded-xl border bg-background text-sm font-medium outline-none focus:ring-2 focus:ring-primary/20 transition-all"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
          >
            <option value="">All Statuses</option>
            <option value="Planning">Planning</option>
            <option value="In Progress">In Progress</option>
            <option value="On Hold">On Hold</option>
            <option value="Completed">Completed</option>
          </select>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-6">
        {loading ? (
          [1, 2, 3].map(i => (
            <div key={i} className="bg-card rounded-2xl border p-6 shadow-sm animate-pulse">
              <div className="h-6 bg-muted rounded w-3/4 mb-3"></div>
              <div className="h-4 bg-muted rounded w-1/4 mb-6"></div>
              <div className="space-y-2">
                <div className="h-4 bg-muted rounded w-full"></div>
                <div className="h-4 bg-muted rounded w-5/6"></div>
              </div>
            </div>
          ))
        ) : projects.length === 0 ? (
          <div className="col-span-full py-16 text-center border rounded-2xl bg-card border-dashed">
            <div className="flex flex-col items-center justify-center text-muted-foreground">
              <div className="bg-muted p-4 rounded-full mb-4">
                <Target className="h-8 w-8 opacity-50" />
              </div>
              <h3 className="text-lg font-semibold text-foreground">No projects found</h3>
              <p className="mt-1">Create a project to start collaborating with your team.</p>
            </div>
          </div>
        ) : (
          projects.map((project) => (
            <div 
              key={project._id} 
              className="bg-card rounded-2xl border shadow-sm hover:shadow-md transition-all flex flex-col group relative overflow-hidden cursor-pointer"
              onClick={() => handleViewDetails(project)}
            >
              <div className="p-6 flex-1">
                <div className="flex justify-between items-start mb-4">
                  <div className="relative inline-flex items-center">
                    <CircleDashed className={`absolute left-2.5 h-3 w-3 pointer-events-none
                      ${project.status === 'In Progress' ? 'text-primary' : ''}
                      ${project.status === 'Completed' ? 'text-success' : ''}
                      ${project.status === 'Planning' ? 'text-muted-foreground' : ''}
                      ${project.status === 'On Hold' ? 'text-warning' : ''}
                    `} />
                    <select
                      value={project.status}
                      onClick={(e) => e.stopPropagation()}
                      onChange={(e) => handleStatusChange(project, e.target.value)}
                      className={`appearance-none cursor-pointer outline-none pl-7 pr-6 py-1 rounded-full text-xs font-semibold transition-colors border border-transparent hover:border-border/50
                        ${project.status === 'In Progress' ? 'bg-primary/10 text-primary' : ''}
                        ${project.status === 'Completed' ? 'bg-success/10 text-success' : ''}
                        ${project.status === 'Planning' ? 'bg-muted text-muted-foreground' : ''}
                        ${project.status === 'On Hold' ? 'bg-warning/10 text-warning' : ''}
                      `}
                    >
                      <option value="Planning" className="text-foreground bg-background">Planning</option>
                      <option value="In Progress" className="text-foreground bg-background">In Progress</option>
                      <option value="On Hold" className="text-foreground bg-background">On Hold</option>
                      <option value="Completed" className="text-foreground bg-background">Completed</option>
                    </select>
                    <div className="absolute right-2 pointer-events-none opacity-50">
                      <svg className="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                    </div>
                  </div>

                  <div className="flex flex-col items-end gap-2">
                    <RoleGuard allowedRoles={['Admin', 'Manager']}>
                      <div className="flex items-center gap-1 bg-background p-0.5 rounded-lg shadow-sm border" onClick={(e) => e.stopPropagation()}>
                        <button 
                          onClick={(e) => { e.stopPropagation(); handleEdit(project); }}
                          className="p-1 text-muted-foreground hover:text-primary hover:bg-primary/10 rounded-md transition-colors"
                        >
                          <Edit className="h-3.5 w-3.5" />
                        </button>
                        <button 
                          onClick={(e) => { e.stopPropagation(); handleDelete(project._id); }}
                          className="p-1 text-muted-foreground hover:text-danger hover:bg-danger/10 rounded-md transition-colors"
                        >
                          <Trash2 className="h-3.5 w-3.5" />
                        </button>
                      </div>
                    </RoleGuard>

                    <span className={`inline-flex items-center gap-1 text-xs font-medium px-2 py-0.5 rounded
                      ${project.priority === 'High' ? 'text-danger bg-danger/10' : 
                        project.priority === 'Medium' ? 'text-warning bg-warning/10' : 
                        'text-muted-foreground bg-muted'}
                    `}>
                      {project.priority === 'High' && <AlertCircle className="h-3 w-3" />}
                      {project.priority === 'Medium' && <Flag className="h-3 w-3" />}
                      {project.priority} Priority
                    </span>
                  </div>
                </div>

                <h3 className="text-xl font-bold text-foreground mb-2 group-hover:text-primary transition-colors">{project.name}</h3>
                <p className="text-sm text-muted-foreground line-clamp-2 mb-6">{project.description}</p>

                <div className="space-y-3">
                  <div className="flex items-center justify-between text-sm">
                    <span className="text-muted-foreground flex items-center gap-2"><Calendar className="h-4 w-4"/> Deadline</span>
                    <span className="font-medium text-foreground">{new Date(project.deadline).toLocaleDateString()}</span>
                  </div>
                  <div className="flex items-center justify-between text-sm">
                    <span className="text-muted-foreground flex items-center gap-2"><Target className="h-4 w-4"/> Client</span>
                    <span className="font-medium text-foreground">{project.clientId?.companyName || 'Internal'}</span>
                  </div>
                </div>
              </div>

              <div className="px-6 py-4 border-t bg-muted/20 flex items-center justify-between">
                <div className="flex -space-x-2">
                  {project.teamMembers?.slice(0, 3).map((member, i) => (
                    <div key={i} className="h-8 w-8 rounded-full border-2 border-background bg-primary/20 flex items-center justify-center text-xs font-bold text-primary">
                      {member.firstName.charAt(0)}{member.lastName.charAt(0)}
                    </div>
                  ))}
                  {project.teamMembers?.length > 3 && (
                    <div className="h-8 w-8 rounded-full border-2 border-background bg-muted flex items-center justify-center text-xs font-medium text-muted-foreground">
                      +{project.teamMembers.length - 3}
                    </div>
                  )}
                  {(!project.teamMembers || project.teamMembers.length === 0) && (
                    <span className="text-xs text-muted-foreground italic">No team assigned</span>
                  )}
                </div>
                <button 
                  onClick={(e) => { e.stopPropagation(); handleViewDetails(project); }}
                  className="text-sm font-medium text-primary hover:underline"
                >
                  View Details
                </button>
              </div>
            </div>
          ))
        )}
      </div>

      {!loading && projects.length > 0 && (
        <div className="flex items-center justify-between pt-4">
          <span className="text-sm text-muted-foreground">
            Showing <span className="font-medium text-foreground">{totalRecords}</span> projects
          </span>
          <div className="flex items-center gap-2">
            <button 
              onClick={() => setPage(p => Math.max(1, p - 1))}
              disabled={page === 1}
              className="px-3 py-1.5 rounded-lg border bg-background text-sm font-medium hover:bg-muted disabled:opacity-50 transition-colors"
            >
              Previous
            </button>
            <button 
              onClick={() => setPage(p => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
              className="px-3 py-1.5 rounded-lg border bg-background text-sm font-medium hover:bg-muted disabled:opacity-50 transition-colors"
            >
              Next
            </button>
          </div>
        </div>
      )}

      <ProjectModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSuccess={() => fetchProjects()}
        project={selectedProject}
      />
      <ProjectDetailsModal
        isOpen={isDetailsModalOpen}
        onClose={() => setIsDetailsModalOpen(false)}
        project={selectedProject}
      />
    </div>
  );
}

messages.message:
Error: Calling setState synchronously within an effect can trigger cascading renders

Effects are intended to synchronize state between React and external systems such as manually updating the DOM, state management libraries, or other platform APIs. In general, the body of an effect should do one or both of the following:
* Update external systems with the latest state from React.
